### Option 1: Interactive 3D House (Three.js)
This code creates a low-poly house with a roof, walls, a door, and a window. It includes lighting, shadows, and orbit controls so you can rotate around the house.

**Instructions:**
1. Copy the code block below.
2. Create a new file on your computer named `house.html`.
3. Paste the code into that file and save it.
4. Double-click `house.html` to open it in your browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMat = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMat = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x4a3c31 }); // Dark wood
        const windowMat = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const grassMat = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 8);
        const floor = new THREE.Mesh(floorGeo, grassMat);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallGeo = new THREE.BoxGeometry(10, 4, 6);
        const walls = new THREE.Mesh(wallGeo, wallMat);
        walls.position.y = 2;
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // Roof
        const roofGeo = new THREE.ConeGeometry(9, 3, 4);
        const roof = new THREE.Mesh(roofGeo, roofMat);
        roof.position.y = 5.5;
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3.5, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 1.75, 3.1); // Front center
        door.castShadow = true;
        houseGroup.add(door);

        // Window
        const winGeo = new THREE.BoxGeometry(2, 1.5, 0.2);
        const windowMesh = new THREE.Mesh(winGeo, windowMat);
        windowMesh.position.set(0, 3, 3.1);
        houseGroup.add(windowMesh);

        // Chimney
        const chimGeo = new THREE.BoxGeometry(1, 2, 1);
        const chimney = new THREE.Mesh(chimGeo, wallMat);
        chimney.position.set(4, 6.5, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
